window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2022>1","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"BASIC CONCEPTS : ROLES OF GOVERNMENT IN AGRICULTURAL DEVELOPMENT","question":"To reduce rural-urban migration, the government should","images":[],"options":{"A":"establish commodity boards","B":"provide social infrastructure","C":"establish tractor-hiring units","D":"provide extension services to farmers"},"answer":"B","explanation":"As a strategy, for reducing Rural \u2013 Urban Migrations in Nigeria, Government should provide housing and adequate social amenities for the rural dwellers","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>2","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"The establishment of cooperative farming is encouraged by governments because it","images":[],"options":{"A":"enables farmers to control soil erosion","B":"facilitates the use of hand tools","C":"enables individual farmers to acquire capital","D":"allows farmers to cultivate small and scattered plots"},"answer":"C","explanation":"It allows little farms to do what big farms can do, like buy inputs at bulk rates, increase volume to open new markets.  Farmers are able to increase their level of production.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>3","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"BASIC CONCEPTS : ROLE OF NON-GOVERNMENTAL ORGANIZATIONS IN AGRICULTURAL DEVELOPMENT","question":"A non-governmental organization involved in agricultural development in West Africa is","images":[],"options":{"A":"Operation Feed the Nation","B":"River Basin Development Authority","C":"Agricultural Development Project","D":"International Institute of Tropical Agriculture"},"answer":"D","explanation":"The International Institute of Tropical Agriculture (IITA) is a nonprofit organisation that works with partners to enhance crop quality and productivity, reduce producer and consumer risks, and generate wealth from agriculture, with the ultimate goals of reducing hunger, malnutrition, and poverty","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>4","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrates a farm implement. Use it to answer the question below.       The illustrated farm implement is used for","images":["data:image/png;base64,"],"options":{"A":"pulverizing soil into fine tilth","B":"breaking up soil into clods","C":"gathering topsoil","D":"levelling soil surface"},"answer":"C","explanation":"A disc plough is a farm tool for turning the soil before sowing seed or planting.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>5","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrates a farm implement. Use it to answer the question below.     The part of the illustrated farm implement which enables it to roll over obstacles is labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"C","explanation":"When the plough is working, the discs roll forward under the action of counter-force from earth and open the soil with its cutting edge.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>6","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below illustrates a farm implement. Use it to answer the question below.     The function of the part labelled II is to","images":["data:image/png;base64,"],"options":{"A":"remove soil","B":"turn soil","C":"break clods","D":"cut stumps"},"answer":"A","explanation":"Disc scraper remove soil that tends to stick to working surface of a disc, for great pulverization to furrow to furrow slice, invert the furrow slice and cover the trash better","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>7","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"A combine harvester can be used simultaneously to harvest","images":[],"options":{"A":"legumes and apply fertilizer","B":"grains and eradicate weeds","C":"tubers and distribute fertilizer","D":"cereals and winnow grains"},"answer":"D","explanation":"combine harvester are used in harvesting and cleaning of cereals such as wheat,barley, maize and rice.  The machine simply combines the three major harvesting operations-reaping, threshing and winnowing into a single process","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>8","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"Ranging poles used in farm surveying have characteristic","images":[],"options":{"A":"green and white bands","B":"blue and white bands","C":"red and white bands","D":"black and red bands"},"answer":"C","explanation":"Ranging poles are used to mark areas and to set out straight lines on the field. They are also used to mark points which must be seen from a distance, in which case a flag may be attached to improve the visibility.  Ranging poles are straight round stalks, 3 to 4 cm thick and about 2 m long. They are made of wood or metal. Ranging poles can also be home made from strong straight bamboo or tree branches.  REMEMBER: Ranging poles may never be curved.  Ranging poles are usually painted with alternate red-white or black-white bands. If possible, wooden ranging poles are reinforced at the bottom end by metal points.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>9","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Decomposition of soil organic matter is mainly caused by","images":[],"options":{"A":"bacterial","B":"algae","C":"fungi","D":"nematodes"},"answer":"A","explanation":"Decomposers are microorganisms that decompose/convert the dead remains of plants and animals into humus.  \u2219 Bacteria are a common example of decomposers.  \u2219 They are crucial in cleaning the waste of dead plants and animals and converting them into humus, which increases the soil's nutrients.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>10","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"The main factors responsible for rock weathering in the desert are high temperature and","images":[],"options":{"A":"animal activity","B":"water","C":"wind","D":"root growth"},"answer":"C","explanation":"Physical forces in the desert that break down rocks include the daily heating and cooling of rocks on the surface, expansion of plant root in cracks, the freezing and melting of ice in cracks, and exposure to wind and precipitation (particularly during storms).","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>11","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"A difference between physical and chemical weathering is that","images":[],"options":{"A":"there is a change in the mineral composition of rock in physical weathering","B":"the mineral composition of rock is changed in chemical weathering","C":"carbonation is necessary in physical weathering","D":"wind is necessary in chemical weathering"},"answer":"B","explanation":"Chemical weathering involves the interaction of rock with mineral solutions (chemicals) to change the composition of rocks. In this process, water interacts with minerals to create various chemical reactions and transform the rocks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>12","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Use the information below to answer the question below.  In an experiment on soil porosity, the following results were obtained:    volume of dry soil =  52cm3  volume of water =  48cm3  volume of soil and water =  78cm3    Determine the volume of airspace in the soil sample","images":[],"options":{"A":"22cm3","B":"26cm3","C":"30cm3","D":"100cm3"},"answer":"A","explanation":"Expected total volume of soil and water = 52cm3 + 48cm3= 100cm3  Actual or given total volume of soil and water = 78cm3  Difference in total volume = 100cm3 - 78cm3  The difference represents air space volume = 22cm3","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>13","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Use the information below to answer the question below.  In an experiment on soil porosity, the following results were obtained:    volume of dry soil =  52cm3  volume of water =  48cm3  volume of soil and water =  78cm3  Calculate the porosity of the soil sample","images":[],"options":{"A":"28.21%","B":"42.31%","C":"45.83%","D":"61.54%"},"answer":"B","explanation":"Porosity of the soil sample = volume of air space in the soil divide volume of soil sample x 100%  22cm3/52cm3 x 100/1 = 2200/52 = 42.31 %","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2022>14","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The diagram below illustrates a tool used to analyse a soil sample in an experiment. Use it to answer the question below.         The aim of the experiment is to determine the soil","images":["data:image/png;base64,"],"options":{"A":"structure","B":"texture","C":"mineral matter","D":"organic matter"},"answer":"B","explanation":"Soil texture is the relative proportions of sand, silt, or clay in a soil. The soil textural class is a grouping of soils based upon these relative proportions. Soils with the finest texture are called clay soils, while soils with the coarsest texture are called sands.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>15","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The diagram below illustrates a tool used to analyse a soil sample in an experiment. Use it to answer the question below.       The part labelled III will contain","images":["data:image/png;base64,"],"options":{"A":"clay","B":"silt","C":"coarse sand","D":"fine sand"},"answer":"D","explanation":"Soil texture is the relative proportions of sand, silt, or clay in a soil. The soil textural class is a grouping of soils based upon these relative proportions. Soils with the finest texture are called clay soils, while soils with the coarsest texture are called sands.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>16","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The diagram below illustrates a tool used to analyse a soil sample in an experiment. Use it to answer the question below.       The diameter of the soil particle that would be retained in the part labelled II is","images":["data:image/png;base64,"],"options":{"A":"0.002-0.02 mm","B":"0.02-0.2 mm","C":"0.2-2.0 mm","D":"2.0 mm"},"answer":"C","explanation":"Soil particlesDiameter range (mm)Coarse sand2.0 - 0.2Fine sand0.2 - 0.02 Silt0.02 - 0.002Clay","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>17","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Potassium deficiency in cereal crops is indicated by","images":[],"options":{"A":"browning of leaves from the tips and margins","B":"yellowing of younger leaves","C":"purpling of leaves","D":"white and irregular spots on leaves"},"answer":"A","explanation":"Potassium deficiency symptoms on cereal grains appear as a burning or scorching of the older, lower leaves. The burning begins at the leaf tip and continues down the leaf margin.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>18","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Nitrogen is important in plants because it is mainly needed in","images":[],"options":{"A":"fruit formation","B":"root development","C":"leaf formation","D":"cell division"},"answer":"D","explanation":"Nitrogen is a vital nutrient for plants as it is a major component of amino acids, proteins, and nucleic acids, which are essential for plant growth and development. Therefore, it is mainly needed in cell division.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>19","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"Water can be conserved in the soil by","images":[],"options":{"A":"mulching, strip cropping and cover cropping","B":"weeding, strip cropping and clean clearing","C":"clean clearing, mulching and strip cropping","D":"cover cropping, mulching and weeding"},"answer":"A","explanation":"Mulching may be defined as the process of covering the soil surface around the plants to create congenial conditions for the crop growth. This may include moisture and soil conservation, temperature moderation, salinity and weed control etc.   Strip Cropping:cultivation in which different crops are sown in alternate strips to prevent soil erosion.  In agriculture, cover crops are plants that are planted to cover the soil rather than for the purpose of being harvested. Cover crops manage soil erosion","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>20","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Monocotyledonous crops include","images":[],"options":{"A":"oil palm, rice and plantain","B":"cowpea, pepper and tomato","C":"garden egg, cassava and mango","D":"rubber, cashew and orange"},"answer":"A","explanation":"Monocot plants have only one cotyledon in their seeds.  Monocots include wheat, maize, bamboo, rice, banana, lilies, orchids, and tulips.  Monocot leaves are small and linear, and they create a sheathing at the base of the stem","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>21","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Swampy lands are most suitable for growing","images":[],"options":{"A":"yam","B":"rice","C":"maize","D":"tomato"},"answer":"B","explanation":"Rice is water loving and does well on soils that hold a lot of water - clay, clay-loamy or loamy. So swampy land which is either clay-loamy or loamy soil depending on the location, and retains a lot of water is suitable for growing rice.  Rice is grown in water primarily to stave off pests, and keep weeds away from the rice fields","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>22","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"If maize seeds are sown at a spacing of 60 cm by 90cm, what is the plant population of maize expected on one hectare of farmland?","images":[],"options":{"A":"18,519 plants","B":"16,667 plants","C":"11,111 plants","D":"5,400 plants"},"answer":"A","explanation":"Plant population/hectare = 100,000,000/60 X 90=100,000,000/5400=18,519 plants","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>23","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The practice of placing the correct number of seeds in the soil with definite intra-row and inter-row spacing is called","images":[],"options":{"A":"seed drilling","B":"centrifugal distribution","C":"precision planting","D":"seed broadcasting"},"answer":"C","explanation":"In agriculture, precision seeding is a method of seeding that involves placing seed at a precise spacing and depth. This is in contrast to broadcast seeding, where seed is scattered over an area.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>24","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"Which of the following groups of crops will thrive in areas with high rainfall?","images":[],"options":{"A":"cotton, cowpea and groundnut","B":"millet, maize and cotton","C":"guinea corn, cowpea and maize","D":"cocoa, oil palm and rubber"},"answer":"D","explanation":"Cocoa, oil palm, and rubber are all crops that thrive in areas with high rainfall. These crops require a lot of water to grow, which is why they do well in areas with high rainfall. Cotton, cowpea, and groundnut, on the other hand, are crops that can tolerate drier conditions. Similarly, millet, maize, and cotton are crops that can grow in areas with moderate rainfall. Guinea corn, cowpea, and maize also require moderate rainfall to grow.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>25","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The diagram below illustrates a crop. Use it to answer the question below       The illustrated crop is","images":["data:image/png;base64,"],"options":{"A":"Capsicum frutescens","B":"Abelmoscus esculentus","C":"Glycine max","D":"Hevea brasiliensis"},"answer":"B","explanation":"okra, ( Abelmoschus esculentus ), herbaceous hairy annual plant of the mallow family (Malvaceae) and its edible fruit.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>26","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The diagram below illustrates a crop. Use it to answer the question below     A disease that could affect the illustrated crop is","images":["data:image/png;base64,"],"options":{"A":"swollen shoot","B":"smut","C":"root knot","D":"rosette"},"answer":"C","explanation":"diseases of the okra plant are the Verticillium wilt, powdery mildew, Ascochyta and Cercospora leaf spots and root knot caused by root nematodes.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>27","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The diagram below illustrates a crop. Use it to answer the question below     The most suitable fertilizer for the production of the illustrated crop is","images":["data:image/png;base64,"],"options":{"A":"muriate of potash","B":"ammonium sulphate","C":"potassium nitrate","D":"single superphosphate"},"answer":"A","explanation":"MOP is used extensively for fertilising pastures, sugar cane, fruit trees, vegetables, and other field crops. Muriate of potash, also known as potassium chloride contains 60% potash. Potash is essential for plant growth and quality.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>28","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Capping is a cultural practice carried out in the cultivation of","images":[],"options":{"A":"carrot","B":"cassava","C":"potato","D":"yam"},"answer":"D","explanation":"Capping The practice of using dry grasses or pieces of wood to cover the spot where yam sett or seed yam is planted either on ridge or mound is called capping.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>29","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Damping off disease of tomato could be controlled by","images":[],"options":{"A":"staking","B":"supplying","C":"thinning","D":"pruning"},"answer":"C","explanation":"Thinning is a term used in agricultural sciences to mean the removal of some plants, or parts of plants, to make room for the growth of others","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>30","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"The most common way of controlling weeds in tree crop plantations is by","images":[],"options":{"A":"crop rotation","B":"hand pulling","C":"flooding","D":"slashing"},"answer":"D","explanation":"Slash and burn agriculture is the process of cutting down the vegetation in a particular plot of land, setting fire to the remaining foliage, and using the ashes to provide nutrients to the soil for the use of planting food crops","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>31","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following crops is correctly matched with a disease that affects it?","images":[],"options":{"A":"maize-smut","B":"sorghum-scab","C":"Rice-black arm","D":"Yam-blast"},"answer":"A","explanation":"Corn smut is a plant disease caused by the pathogenic fungus Ustilago maydis that causes smut on maize","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>32","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Soil-borne diseases could be controlled in the nursery by","images":[],"options":{"A":"mulching","B":"manuring","C":"heat treatment","D":"provision of shade"},"answer":"C","explanation":"Soil solarization is the possible way to control or prevent these soil pathogens through raising of soil temperature. Clean thin and transparent polythene sheet can be spread over the nursery soil. Solar energy will be trapped in this method and heats the soil This removes all the soil pathogens","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>33","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Use the information below to answer the question below    I  Yellowing of leaves  II  Raised brown spots on the leaves  III Drying up of leaves  IV  Exudation of gum    The disease of citrus described above is","images":[],"options":{"A":"die-back","B":"gummosis","C":"tristeza","D":"blight"},"answer":"B","explanation":"The symptoms described in the question are characteristic of gummosis, a disease that affects citrus trees. Gummosis is a disease that causes the tree to exude a gum-like substance, often accompanied by yellowing and drying up of leaves, and raised brown spots on the leaves. Therefore, the correct answer is gummosis.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>34","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below illustrates the digestive system of a farm animal. Use it to answer the question below.         The diagram illustrates the digestive system of a","images":["data:image/png;base64,"],"options":{"A":"chicken","B":"turkey","C":"sheep","D":"rabbit"},"answer":"D","explanation":"The digestive system consists of the alimentary canal and the digestive glands.  ALIMENTARY CANAL  Rabbit is an herbivorous animal, therefore, its alimentary canal is long, so as to obtain sufficient nourishment from the vegetable matter.  The alimentary canal is a long, coiled tube of variable diameter.  It is suspended in the body cavity by the mesentery.  It consists of mouth, tongue, teeth, bucco-pharyngeal cavity.  oesophagus, stomach, small intestine, large intestine and anus","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>35","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below illustrates the digestive system of a farm animal. Use it to answer the question below.       The part labelled III is the","images":["data:image/png;base64,"],"options":{"A":"pancreas","B":"caecum","C":"small intestine","D":"large intestine"},"answer":"B","explanation":"cecum, also spelled caecum, pouch or large tubelike structure in the lower abdominal cavity that receives undigested food material from the small intestine","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>36","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The diagram below illustrates the digestive system of a farm animal. Use it to answer the question below.       Digestion of fats takes place in the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"The jejunum is the middle section of the small intestine. Many nutrients, such as amino acids, fatty acids, and glucose, are absorbed here. The last section of the small intestine is the ileum. In the ileum, the remaining digested nutrients are absorbed, as well as the B vitamins","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>37","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Lactation normally occurs","images":[],"options":{"A":"at the onset of conception","B":"at the onset of puberty","C":"after gestation","D":"after mating"},"answer":"C","explanation":"Lactation is the period of time that a mother secretes milk from her mammary glands. The lactation cycle is the period between one calving and the next.   gestation, in mammals, the time between conception and birth, during which the embryo or fetus is developing in the uterus.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>38","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A by-product of all livestock is","images":[],"options":{"A":"hide","B":"horn","C":"milk","D":"meat"},"answer":"A","explanation":"Hides and skins are one of the by-products in animal production. They are an important and valuable resource used for shoes, bags etc.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>39","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Removal of needle teeth is important in the management of","images":[],"options":{"A":"kids","B":"lambs","C":"calves","D":"piglets"},"answer":"D","explanation":"Piglets are born with outwardly projecting canine or \"needle\" teeth used in competition with littermates for teat access.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>40","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"Which of the following farm animals will browse more on plants in a pasture?","images":[],"options":{"A":"Goats","B":"Cattle","C":"Pigs","D":"Sheep"},"answer":"A","explanation":"Goats are characterized by an extensive browsing habit with the preference for woody plants and broadleaved tree species","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>41","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"The main reason for castrating farm animals is to","images":[],"options":{"A":"remove male odour","B":"make the animal sterile","C":"increase meat production","D":"make them lose weight"},"answer":"B","explanation":"Castration is defined as the destruction or removal of the testes, epididymis, and a part of spermatic cord from a male animal e.g. ram, buck, bull. Male animals that are reserved for fattening and those that are not needed for breeding or mating should be castrated.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>42","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Which of the following statements about silage are true? It    I.   has laxative effect  II.  is acidic in reaction  III. has a strong aroma when well prepared","images":[],"options":{"A":"I  and II only","B":"I  and III only","C":"II  and III only","D":"I, II  and III"},"answer":"D","explanation":"Characteristics of Good Silage  -No mould growth.  -Pleasant fruity odour/ an acceptable aroma.  -Liked very much by animals because of mild-acidic taste and pleasant aroma.  -Free flowing and non-sticky texture.  -3-4% increased palatability.  -Increased nutritive value.  -pH around 4.0-4.5.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>43","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"If 200 layers require 25kg of layer mash per day, calculate the quantity of feed required by 1000 layers per day","images":[],"options":{"A":"5kg","B":"40kg","C":"80kg","D":"125kg"},"answer":"D","explanation":"200layers =25kg  1000layers = x  x represent quantity of feed  cross multiply  x = 1000 X 25/200  x=125kg","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>44","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Salt licks are provided for grazing animals to","images":[],"options":{"A":"make the pasture palatable","B":"supply nutrients in pastures","C":"supplement mineral intake","D":"provide laxatives"},"answer":"C","explanation":"Salt lick is usually given to ruminant animals to supplement for essential minerals needed by their body.  Salt licks are deposit of mineral salts used by animals to supplement their nutrition, ensuring enough minerals in their diets. A wide assortment of animals, primarily herbivores use salt licks to get essential nutrients like calcium magnesium, sodium and zinc","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>45","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"The correct order of arrangement of ration for piglets from day old is","images":[],"options":{"A":"weaners----> growers---->creep---->finisher","B":"creep---->weaners---->growers---->finisher","C":"growers---->finisher---->creep---->weaners","D":"finisher---->creep---->weaners---->growers"},"answer":"B","explanation":"Creep feed and starter feeds are highly specialist and contain additives to improve digestion and gut integrity.   The transition at weaning can be smoothed with creep feed, to minimise growth checks  Grower pigs are capable of using higher digestible proteins such as soya, combined with raw cereals  A grower ration may include wheat, barley, high protein soya and possibly rape meal  Healthy pigs in good environments that are moving into the early finishing stage are entering an unprecedented phase of rapid lean growth.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>46","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"In farming enterprise, short term loans are used to","images":[],"options":{"A":"purchase farm machinery","B":"construct new farm buildings","C":"construct an irrigation dam","D":"purchase agrochemicals"},"answer":"D","explanation":"A short term loan is a type of loan that is obtained to support a temporary personal or business capital need. As it is a type of credit, it involves repaying the principle amount with interest by a given due date, which is usually within a year from getting the loan","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2022>47","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"The table below illustrates a farm record for Goodness Farms in the year 1970. Use it to answer the question below.  DateNumber of hensTotal eggs collectedTotal eggs sold4th June362176965th June3601991086th June36017748    The table illustrates","images":[],"options":{"A":"an inventory record","B":"a production record","C":"a labour record","D":"an input record"},"answer":"B","explanation":"Production records are used to document everything that is produced on the farm. These records are prepared every week. And then summed up at the end of the month and also at the end of the year. Thus, there is a weekly record, a monthly record, and an annual record of everything produced on the farm","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>48","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"The table below illustrates a farm record for Goodness Farms in the year 1970. Use it to answer the question below.  DateNumber of hensTotal eggs collectedTotal eggs sold4th June362176965th June3601991086th June36017748  Calculate the total amount of eggs sold on the farm","images":[],"options":{"A":"804","B":"552","C":"300","D":"252"},"answer":"D","explanation":"total amount of eggs sold on the farm = 96 + 108 + 48  =252","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2022>49","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM RECORDS AND ACCOUNTS","question":"The table below illustrates a farm record for Goodness Farms in the year 1970. Use it to answer the question below.  DateNumber of hensTotal eggs collectedTotal eggs sold4th June362176965th June3601991086th June36017748  If all the unsold eggs were later sold on 7th June at \u20a65.00 per crate, calculate the income from unsold eggs.(Assuming a crate = 30eggs)","images":[],"options":{"A":"\u20a640.00","B":"\u20a645.00","C":"\u20a650.00","D":"\u20a655.00"},"answer":"C","explanation":"4th June = 80  5th June = 91  6th June = 129    Total unsold eggs = 80+ 91 129  =300  1 crate = 30eggs,   price per crate = \u20a65.00    no of crates of unsold eggs later sold on 7th June = 300/30  =10 crates  Income from unsold eggs = no of crates of unsold eggs later sold on 7th June X  price per crate  10 X 5  =\u20a650","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2022>50","subject":"Agricultural Science","year":"2022","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"The gross profit of a farm business is the farm's","images":[],"options":{"A":"net sales less cost of production","B":"total sales less operating expenses","C":"net sales less taxation","D":"total sales less cost of production"},"answer":"D","explanation":"The gross profit of a farm business is calculated as the total sales less the cost of production. This is because gross profit is a measure of a company's profitability before operating expenses, taxes, and interest payments are deducted. It is calculated by subtracting the cost of goods sold (COGS) from total sales. Therefore, the correct answer is 'total sales less cost of production'.","marks":"1","difficulty":"2"}];